const canvas = document.getElementById('game-canvas');
const ctx = canvas.getContext('2d');

const overlayCanvas = document.createElement('canvas');
const overlayCtx = overlayCanvas.getContext('2d');

// 깔끔한 대나무 패턴 생성 (코드로 직접 그려서 배경 투명하고 난잡하지 않게)
const bambooTile = document.createElement('canvas');
bambooTile.width = 60;
bambooTile.height = 60;
const bCtx = bambooTile.getContext('2d');
// 대나무 줄기
bCtx.fillStyle = '#2e7d32';
bCtx.fillRect(26, 0, 8, 60);
bCtx.fillStyle = '#4caf50';
bCtx.fillRect(26, 15, 8, 2);
bCtx.fillRect(26, 35, 8, 2);
bCtx.fillRect(26, 55, 8, 2);
// 잎사귀
bCtx.fillStyle = '#388e3c';
bCtx.beginPath(); bCtx.ellipse(18, 15, 12, 4, Math.PI/4, 0, Math.PI*2); bCtx.fill();
bCtx.beginPath(); bCtx.ellipse(42, 25, 12, 4, -Math.PI/4, 0, Math.PI*2); bCtx.fill();
bCtx.beginPath(); bCtx.ellipse(18, 40, 12, 4, Math.PI/4, 0, Math.PI*2); bCtx.fill();

let bambooPattern = null;

// 커스텀 사냥꾼 맥 이모지 로드 (Data URI로 로드하여 CORS 회피 및 배경 투명화)
const hunterImg = new Image();
hunterImg.src = "data:image/png;base64,";
const hunterCanvas = document.createElement('canvas');
const hunterCtx = hunterCanvas.getContext('2d');
hunterImg.onload = () => {
  hunterCanvas.width = 60;
  hunterCanvas.height = 60;
  hunterCtx.drawImage(hunterImg, 0, 0, 60, 60);
  const imgData = hunterCtx.getImageData(0, 0, 60, 60);
  const data = imgData.data;
  
  // 흰색 배경 투명화 (가장자리 안티앨리어싱 포함)
  for (let i = 0; i < data.length; i += 4) {
    const r = data[i], g = data[i+1], b = data[i+2];
    const avg = (r + g + b) / 3;
    
    if (avg > 230) {
      data[i+3] = 0; // 투명
    } else if (avg > 180) {
      // 밝은 회색 테두리 반투명 처리
      data[i+3] = Math.max(0, 255 - (avg - 180) * 3);
    }
  }
  hunterCtx.putImageData(imgData, 0, 0);
};

const UI = {
  stageNumber: document.getElementById('stage-number'),
  hearts: document.querySelectorAll('.heart'),
  hintBox: document.getElementById('hint-box'),
  hintText: document.getElementById('hint-text'),
  startScreen: document.getElementById('start-screen'),
  gameOverScreen: document.getElementById('game-over-screen'),
  clearScreen: document.getElementById('clear-screen'),
  startBtn: document.getElementById('start-btn'),
  restartBtn: document.getElementById('restart-btn'),
  replayBtn: document.getElementById('replay-btn'),
};

const GRID_SIZE = 60;
const MAX_STAGE = 7;
const MAX_HP = 3;

let state = {
  mode: 'START',
  hp: MAX_HP,
  stage: 1,
  player: { x: 0, y: 0, animX: 0, animY: 0 },
  camera: { x: 0, y: 0 },
  target: null,
  options: [],
  particles: [],
  hunterPos: null, // 사냥꾼 위치
  familyDiscovered: false,
  sightRadius: 140,
  sightExpands: false
};

function resize() {
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
  overlayCanvas.width = canvas.width;
  overlayCanvas.height = canvas.height;
  bambooPattern = overlayCtx.createPattern(bambooTile, 'repeat');
}
window.addEventListener('resize', resize);
resize();

function coordToWorld(cx, cy) {
  return { x: cx * GRID_SIZE, y: -cy * GRID_SIZE };
}

function worldToCoord(wx, wy) {
  return { x: Math.round(wx / GRID_SIZE), y: -Math.round(wy / GRID_SIZE) };
}

function getCameraOffset() {
  return {
    x: canvas.width / 2 - state.camera.x,
    y: canvas.height / 2 - state.camera.y
  };
}

function randInt(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function generateStage() {
  // 카메라가 팬더 중심일 때 모든 선택지가 화면 안에 들어오도록 거리 계산
  const maxDx = Math.max(1, Math.floor((canvas.width / 2 - 150) / GRID_SIZE));
  const maxDy = Math.max(1, Math.floor((canvas.height / 2 - 200) / GRID_SIZE));
  
  let dx = 0, dy = 0;
  // 7스테이지는 연출을 위해 최소 거리를 어느 정도 멀게 확보
  let minDist = state.stage === 7 ? Math.max(2, Math.floor((maxDx + maxDy) * 0.5)) : 0;
  
  while (dx === 0 && dy === 0) {
    dx = randInt(-maxDx, maxDx);
    dy = randInt(-maxDy, maxDy);
    if (state.stage === 7 && (Math.abs(dx) + Math.abs(dy)) < minDist) {
      dx = 0; dy = 0; // 너무 가까우면 다시 뽑기
    }
  }
  
  const tx = state.player.x + dx;
  const ty = state.player.y + dy;
  state.target = { x: tx, y: ty };
  
  state.options = [];
  state.options.push({ x: tx, y: ty, isCorrect: true, pathAxis: Math.random() < 0.5 ? 'x' : 'y' });
  
  const distractors = [];
  if (tx !== ty) distractors.push({ x: ty, y: tx });
  if (tx !== 0) distractors.push({ x: -tx, y: ty });
  if (ty !== 0) distractors.push({ x: tx, y: -ty });
  distractors.push({ x: tx + randInt(-2, 2), y: ty + randInt(-2, 2) });
  distractors.push({ x: tx + randInt(-3, 3), y: ty + randInt(-3, 3) });

  let uniqueDistractors = [];
  distractors.forEach(d => {
    if (d.x === tx && d.y === ty) return;
    if (Math.abs(d.x - state.player.x) > maxDx || Math.abs(d.y - state.player.y) > maxDy) return; // 화면 밖 오답 제외
    if (uniqueDistractors.some(ud => ud.x === d.x && ud.y === d.y)) return;
    uniqueDistractors.push(d);
  });
  
  // 오답이 너무 적게 남았을 경우 강제로 생성하여 최소 3개의 선택지가 되도록 보장
  while (uniqueDistractors.length < 2) {
    let randX = state.player.x + randInt(-maxDx, maxDx);
    let randY = state.player.y + randInt(-maxDy, maxDy);
    if ((randX !== tx || randY !== ty) && !uniqueDistractors.some(ud => ud.x === randX && ud.y === randY)) {
      uniqueDistractors.push({ x: randX, y: randY });
    }
  }
  
  // 섞은 후 최대 3개 뽑기
  uniqueDistractors.sort(() => Math.random() - 0.5);
  uniqueDistractors.slice(0, 3).forEach(d => {
    state.options.push({ x: d.x, y: d.y, isCorrect: false, pathAxis: Math.random() < 0.5 ? 'x' : 'y' });
  });
  
  state.options.sort(() => Math.random() - 0.5);
  
  const hintTypes = [
    `안전한 곳은 (${tx}, ${ty})야!`,
    `x좌표가 ${tx}이고, y좌표가 ${ty}인 곳으로 가자!`,
    `y좌표가 ${ty}이고, x좌표가 ${tx}인 곳이 안전해!`,
  ];
  let hintStr = hintTypes[randInt(0, hintTypes.length - 1)];
  
  if (tx === 0) hintStr = `y축 위에 있고 y좌표가 ${ty}인 곳을 찾아!`;
  if (ty === 0) hintStr = `x축 위에 있고 x좌표가 ${tx}인 곳을 찾아!`;
  
  UI.hintText.innerText = hintStr;
  UI.hintBox.classList.remove('hidden');
  UI.stageNumber.innerText = state.stage;
}

function updateHPUI() {
  UI.hearts.forEach((h, idx) => {
    if (idx < state.hp) h.classList.add('active');
    else h.classList.remove('active');
  });
}

function initGame() {
  state.hp = MAX_HP;
  state.stage = 1;
  state.player = { x: 0, y: 0, animX: 0, animY: 0 };
  state.camera = { x: 0, y: 0 };
  state.mode = 'PLAY';
  state.particles = [];
  state.hunterPos = null;
  state.familyDiscovered = false;
  state.sightRadius = 140;
  state.sightExpands = false;
  
  UI.startScreen.classList.add('hidden');
  UI.gameOverScreen.classList.add('hidden');
  UI.clearScreen.classList.add('hidden');
  
  updateHPUI();
  generateStage();
}

function spawnParticles(wx, wy, color) {
  for(let i=0; i<20; i++) {
    state.particles.push({
      x: wx, y: wy,
      vx: (Math.random()-0.5)*12,
      vy: (Math.random()-0.5)*12,
      life: 1.0,
      color: color
    });
  }
}

function getPathPos(pStart, opt, p) {
  const pWorld = coordToWorld(pStart.x, pStart.y);
  const oWorld = coordToWorld(opt.x, opt.y);
  let cornerWorld;
  if (opt.pathAxis === 'x') {
    cornerWorld = coordToWorld(opt.x, pStart.y);
  } else {
    cornerWorld = coordToWorld(pStart.x, opt.y);
  }

  const dist1 = Math.abs(cornerWorld.x - pWorld.x) + Math.abs(cornerWorld.y - pWorld.y);
  const dist2 = Math.abs(oWorld.x - cornerWorld.x) + Math.abs(oWorld.y - cornerWorld.y);
  const totalDist = dist1 + dist2;
  
  if (totalDist === 0) return pWorld;
  
  const thresh = dist1 / totalDist;
  
  if (p <= thresh) {
    const t = thresh === 0 ? 0 : p / thresh;
    return {
      x: pWorld.x + (cornerWorld.x - pWorld.x) * t,
      y: pWorld.y + (cornerWorld.y - pWorld.y) * t
    };
  } else {
    const t = (p - thresh) / (1 - thresh);
    return {
      x: cornerWorld.x + (oWorld.x - cornerWorld.x) * t,
      y: cornerWorld.y + (oWorld.y - cornerWorld.y) * t
    };
  }
}

function handleOptionClick(opt) {
  if (state.mode !== 'PLAY') return;
  state.mode = 'ANIMATING';
  UI.hintBox.classList.add('hidden');
  
  const startPos = { x: state.player.x, y: state.player.y };
  
  if (opt.isCorrect) {
    let p = 0;
    let isStage7 = (state.stage === 7);
    let speed = isStage7 ? 0.01 : 0.02; // 7스테이지면 처음엔 느리게
    let paused = false;
    
    if (isStage7) {
      state.sightExpands = true; // 시야 점점 넓어지기 시작
    }
    
    // 7스테이지 시야 계산용 (사냥꾼과 동일)
    const pWorld = coordToWorld(startPos.x, startPos.y);
    const oWorld = coordToWorld(opt.x, opt.y);
    let cornerWorld;
    if (opt.pathAxis === 'x') {
      cornerWorld = coordToWorld(opt.x, startPos.y);
    } else {
      cornerWorld = coordToWorld(startPos.x, opt.y);
    }
    const totalDist = Math.abs(cornerWorld.x - pWorld.x) + Math.abs(cornerWorld.y - pWorld.y) + Math.abs(oWorld.x - cornerWorld.x) + Math.abs(oWorld.y - cornerWorld.y);
    // 더 일찍 가족을 발견하도록 수정 (거리가 350 남았을 때 또는 진행률이 30%일 때)
    const triggerP = Math.max(0.1, 1 - 350 / Math.max(totalDist, 1));
    
    const animInterval = setInterval(() => {
      if (paused) return;
      p += speed;
      
      // 7스테이지: 근처에 가면 발견하고 정지
      if (isStage7 && !state.familyDiscovered && p >= triggerP) {
        state.familyDiscovered = true;
        state.player.showExclamation = true;
        paused = true;
        
        // 0.7초 정지 후 빠르게 달려감
        setTimeout(() => {
          paused = false;
          speed = 0.04; // 발견 후 원래 속도의 2배
        }, 700);
      }
      
      if (p >= 1) {
        clearInterval(animInterval);
        state.player.x = opt.x;
        state.player.y = opt.y;
        const targetWorld = coordToWorld(opt.x, opt.y);
        state.player.animX = targetWorld.x;
        state.player.animY = targetWorld.y;
        spawnParticles(targetWorld.x, targetWorld.y, '#4CAF50');
        
        state.player.showExclamation = false; // 도착하면 느낌표 지움
        
        setTimeout(() => {
          if (state.stage >= MAX_STAGE) {
            state.mode = 'CLEAR';
            UI.clearScreen.classList.remove('hidden');
          } else {
            state.stage++;
            generateStage();
            state.mode = 'PLAY';
          }
        }, 800);
      } else {
        const pos = getPathPos(startPos, opt, p);
        state.player.animX = pos.x;
        state.player.animY = pos.y;
      }
    }, 16);
  } else {
    // 오답 애니메이션 (사냥꾼 조우 및 도망)
    let p = 0;
    let returning = false;
    let paused = false;
    
    // 거리 계산하여 적절한 조우 시점(p) 계산
    const pWorld = coordToWorld(startPos.x, startPos.y);
    const oWorld = coordToWorld(opt.x, opt.y);
    let cornerWorld;
    if (opt.pathAxis === 'x') {
      cornerWorld = coordToWorld(opt.x, startPos.y);
    } else {
      cornerWorld = coordToWorld(startPos.x, opt.y);
    }
    const totalDist = Math.abs(cornerWorld.x - pWorld.x) + Math.abs(cornerWorld.y - pWorld.y) + Math.abs(oWorld.x - cornerWorld.x) + Math.abs(oWorld.y - cornerWorld.y);
    
    // 시야(140)를 고려해 약 110픽셀 앞에서 발견하도록 설정 (단, 무조건 최소 10%는 이동한 뒤 발견)
    const triggerP = Math.max(0.1, 1 - 110 / Math.max(totalDist, 1));
    
    const animInterval = setInterval(() => {
      if (paused) return;
      
      if (!returning) {
        p += 0.02; // 가는 속도 (정상)
        if (p >= triggerP) { // 거리에 비례하여 멀리서 발견
          paused = true; // 정지
          state.hunterPos = { x: opt.x, y: opt.y }; // 사냥꾼 등장
          state.player.showExclamation = true; // 놀람 표시
          
          const oWorld = coordToWorld(opt.x, opt.y);
          spawnParticles(oWorld.x, oWorld.y, '#f44336');
          state.hp--;
          updateHPUI();
          
          // 0.8초간 정지하여 놀라는 모습 보여준 후 도망 시작
          setTimeout(() => {
            paused = false;
            returning = true;
          }, 800);
        }
      } else {
        p -= 0.04; // 원래 속도의 2배로 도망침
        if (p <= 0) {
          clearInterval(animInterval);
          state.hunterPos = null; // 사냥꾼 사라짐
          state.player.showExclamation = false; // 놀람 표시 제거
          
          const startWorld = coordToWorld(startPos.x, startPos.y);
          state.player.animX = startWorld.x;
          state.player.animY = startWorld.y;
          
          if (state.hp <= 0) {
            state.mode = 'GAMEOVER';
            UI.gameOverScreen.classList.remove('hidden');
          } else {
            UI.hintBox.classList.remove('hidden');
            state.mode = 'PLAY';
          }
        }
      }
      
      if (!paused) {
        const pos = getPathPos(startPos, opt, p);
        state.player.animX = pos.x;
        state.player.animY = pos.y;
      }
    }, 16);
  }
}

canvas.addEventListener('click', (e) => {
  if (state.mode !== 'PLAY') return;
  const offset = getCameraOffset();
  const clickWorldX = e.clientX - offset.x;
  const clickWorldY = e.clientY - offset.y;
  
  const clickCoord = worldToCoord(clickWorldX, clickWorldY);
  const clickedOpt = state.options.find(o => o.x === clickCoord.x && o.y === clickCoord.y);
  if (clickedOpt) handleOptionClick(clickedOpt);
});

function drawDirtPath(ctx, startW, opt, offset) {
  const cornerW = opt.pathAxis === 'x' ? coordToWorld(opt.x, worldToCoord(startW.x, startW.y).y) : coordToWorld(worldToCoord(startW.x, startW.y).x, opt.y);
  const oW = coordToWorld(opt.x, opt.y);
  
  // 흙길
  ctx.strokeStyle = '#5D4037';
  ctx.lineWidth = 40; // 넉넉한 길 너비
  ctx.lineJoin = 'round';
  ctx.beginPath();
  ctx.moveTo(startW.x + offset.x, startW.y + offset.y);
  ctx.lineTo(cornerW.x + offset.x, cornerW.y + offset.y);
  ctx.lineTo(oW.x + offset.x, oW.y + offset.y);
  ctx.stroke();

  // 중앙 점선
  ctx.strokeStyle = '#795548';
  ctx.lineWidth = 4;
  ctx.setLineDash([10, 10]);
  ctx.stroke();
  ctx.setLineDash([]);
}

function updateAndDraw() {
  // 시야 확장 로직
  if (state.sightExpands) {
    state.sightRadius = Math.min(Math.max(canvas.width, canvas.height) * 1.5, state.sightRadius + 12);
  }

  // 시야는 항상 팬더가 중심!
  const targetCamWorldX = state.mode === 'ANIMATING' ? state.player.animX : state.player.x * GRID_SIZE;
  const targetCamWorldY = state.mode === 'ANIMATING' ? state.player.animY : -state.player.y * GRID_SIZE;
  
  state.camera.x += (targetCamWorldX - state.camera.x) * 0.1;
  state.camera.y += (targetCamWorldY - state.camera.y) * 0.1;
  
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  const offset = getCameraOffset();
  
  // --- 바닥 모눈종이 및 축 그리기 ---
  const startX = Math.floor(-offset.x / GRID_SIZE) * GRID_SIZE;
  const endX = startX + canvas.width + GRID_SIZE * 2;
  const startY = Math.floor(-offset.y / GRID_SIZE) * GRID_SIZE;
  const endY = startY + canvas.height + GRID_SIZE * 2;
  
  for (let x = startX; x < endX; x += GRID_SIZE) {
    ctx.strokeStyle = x === 0 ? 'rgba(255, 255, 255, 0.7)' : 'rgba(100, 255, 100, 0.4)';
    ctx.lineWidth = x === 0 ? 3 : 1;
    ctx.beginPath();
    ctx.moveTo(x + offset.x, 0);
    ctx.lineTo(x + offset.x, canvas.height);
    ctx.stroke();
  }
  
  for (let y = startY; y < endY; y += GRID_SIZE) {
    ctx.strokeStyle = y === 0 ? 'rgba(255, 255, 255, 0.7)' : 'rgba(100, 255, 100, 0.4)';
    ctx.lineWidth = y === 0 ? 3 : 1;
    ctx.beginPath();
    ctx.moveTo(0, y + offset.y);
    ctx.lineTo(canvas.width, y + offset.y);
    ctx.stroke();
  }
  
  // --- 흙길 및 마커 그리기 ---
  if (state.mode === 'PLAY' || state.mode === 'ANIMATING') {
    const pWorld = state.mode === 'ANIMATING' ? {x: state.player.animX, y: state.player.animY} : coordToWorld(state.player.x, state.player.y);
    const startW = coordToWorld(state.player.x, state.player.y);
    
    // 길
    if (state.mode === 'PLAY') {
      state.options.forEach(opt => drawDirtPath(ctx, startW, opt, offset));
    }
    
    // 마커
    if (state.mode === 'PLAY') {
      state.options.forEach(opt => {
        const oWorld = coordToWorld(opt.x, opt.y);
        ctx.fillStyle = 'rgba(255, 200, 0, 0.9)';
        ctx.beginPath();
        ctx.arc(oWorld.x + offset.x, oWorld.y + offset.y, 20, 0, Math.PI * 2);
        ctx.fill();
        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 2;
        ctx.stroke();
      });
    }
  }
  
  // 파티클
  for (let i = state.particles.length - 1; i >= 0; i--) {
    let p = state.particles[i];
    p.x += p.vx; p.y += p.vy; p.life -= 0.05;
    if (p.life <= 0) { state.particles.splice(i, 1); continue; }
    ctx.globalAlpha = p.life;
    ctx.fillStyle = p.color;
    ctx.beginPath();
    ctx.arc(p.x + offset.x, p.y + offset.y, 5, 0, Math.PI * 2);
    ctx.fill();
    ctx.globalAlpha = 1.0;
  }
  
  // --- 대나무 숲 오버레이 (맵 전체를 덮고 길만 뚫기) ---
  overlayCtx.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);
  
  // 전 맵을 대나무 패턴으로 덮기
  overlayCtx.globalCompositeOperation = 'source-over';
  overlayCtx.fillStyle = bambooPattern || 'rgba(10, 30, 10, 0.9)';
  overlayCtx.fillRect(0, 0, overlayCanvas.width, overlayCanvas.height);
  // 전체적으로 약간 어둡게 (안개 효과)
  overlayCtx.fillStyle = 'rgba(0, 0, 0, 0.5)';
  overlayCtx.fillRect(0, 0, overlayCanvas.width, overlayCanvas.height);
  
  // 이동 길에서만 대나무가 사라지도록 구멍 뚫기
  overlayCtx.globalCompositeOperation = 'destination-out';
  overlayCtx.fillStyle = 'rgba(255, 255, 255, 1)';
  overlayCtx.filter = 'blur(10px)'; // 자연스럽게 구멍 뚫기
  
  if (state.mode === 'PLAY' || state.mode === 'ANIMATING') {
    const pWorld = state.mode === 'ANIMATING' ? {x: state.player.animX, y: state.player.animY} : coordToWorld(state.player.x, state.player.y);
    const startW = coordToWorld(state.player.x, state.player.y);
    
    // 팬더 주변 크게 뚫기 (시야 확장 연동)
    overlayCtx.beginPath();
    overlayCtx.arc(pWorld.x + offset.x, pWorld.y + offset.y, state.sightRadius, 0, Math.PI * 2);
    overlayCtx.fill();
    
    // 경로 뚫기
    if (state.mode === 'PLAY') {
      state.options.forEach(opt => {
        const oWorld = coordToWorld(opt.x, opt.y);
        const cornerW = opt.pathAxis === 'x' ? coordToWorld(opt.x, worldToCoord(startW.x, startW.y).y) : coordToWorld(worldToCoord(startW.x, startW.y).x, opt.y);
        
        overlayCtx.strokeStyle = 'rgba(255, 255, 255, 1)';
        overlayCtx.lineWidth = 55; // 흙길 너비에 맞게 대나무를 지움
        overlayCtx.lineJoin = 'round';
        overlayCtx.beginPath();
        overlayCtx.moveTo(startW.x + offset.x, startW.y + offset.y);
        overlayCtx.lineTo(cornerW.x + offset.x, cornerW.y + offset.y);
        overlayCtx.lineTo(oWorld.x + offset.x, oWorld.y + offset.y);
        overlayCtx.stroke();
        
        // 도착 지점 크게 뚫기
        overlayCtx.beginPath();
        overlayCtx.arc(oWorld.x + offset.x, oWorld.y + offset.y, 60, 0, Math.PI * 2);
        overlayCtx.fill();
      });
    }
  }
  
  // 오버레이 적용
  overlayCtx.filter = 'none';
  ctx.drawImage(overlayCanvas, 0, 0);

  // 안개 위로 모눈종이와 축을 선명하게 그립니다.
  for (let x = startX; x < endX; x += GRID_SIZE) {
    ctx.strokeStyle = x === 0 ? 'rgba(255, 255, 255, 0.8)' : 'rgba(100, 255, 100, 0.6)';
    ctx.lineWidth = x === 0 ? 3 : 1;
    ctx.beginPath();
    ctx.moveTo(x + offset.x, 0);
    ctx.lineTo(x + offset.x, canvas.height);
    ctx.stroke();
  }
  
  for (let y = startY; y < endY; y += GRID_SIZE) {
    ctx.strokeStyle = y === 0 ? 'rgba(255, 255, 255, 0.8)' : 'rgba(100, 255, 100, 0.6)';
    ctx.lineWidth = y === 0 ? 3 : 1;
    ctx.beginPath();
    ctx.moveTo(0, y + offset.y);
    ctx.lineTo(canvas.width, y + offset.y);
    ctx.stroke();
  }

  // 좌표 숫자를 렌더링
  ctx.fillStyle = '#ffffff';
  ctx.shadowColor = 'rgba(0,0,0,0.8)';
  ctx.shadowBlur = 4;
  ctx.font = '16px Jua';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  
  let xAxisY = offset.y;
  if (xAxisY < 80) xAxisY = 80; 
  if (xAxisY > canvas.height - 120) xAxisY = canvas.height - 120; 
  
  for (let x = startX; x < endX; x += GRID_SIZE) {
    const val = Math.round(x / GRID_SIZE);
    if (val !== 0) ctx.fillText(val, x + offset.x, xAxisY + 15);
  }
  
  let yAxisX = offset.x;
  if (yAxisX < 20) yAxisX = 20; 
  if (yAxisX > canvas.width - 20) yAxisX = canvas.width - 20; 
  
  for (let y = startY; y < endY; y += GRID_SIZE) {
    const val = -Math.round(y / GRID_SIZE);
    if (val !== 0) ctx.fillText(val, yAxisX - 15, y + offset.y);
  }
  
  ctx.fillText('0', offset.x - 15, offset.y + 15);
  ctx.shadowColor = 'transparent'; // 그림자 리셋

  // --- 플레이어와 캐릭터 렌더링을 맨 마지막으로 이동 (항상 최상단 보장) ---
  if (state.mode === 'PLAY' || state.mode === 'ANIMATING') {
    const pWorld = state.mode === 'ANIMATING' ? {x: state.player.animX, y: state.player.animY} : coordToWorld(state.player.x, state.player.y);
    
    // 7스테이지(마지막) 정답 위치에 팬더 가족 대기 연출 (발견했을 때만)
    if (state.stage === 7 && state.familyDiscovered) {
      const target = state.options.find(o => o.isCorrect);
      if (target) {
        const tWorld = coordToWorld(target.x, target.y);
        ctx.font = '40px Arial';
        ctx.fillText('🐼🐼', tWorld.x + offset.x - 15, tWorld.y + offset.y - 15);
        ctx.font = '30px Arial'; // 아기팬더 한 마리 더
        ctx.fillText('🐼', tWorld.x + offset.x + 28, tWorld.y + offset.y - 10);
      }
    }
    
    // 사냥꾼 등장 연출 (원형 초록 테두리 프레임 적용)
    if (state.hunterPos) {
      const hWorld = coordToWorld(state.hunterPos.x, state.hunterPos.y);
      const cx = hWorld.x + offset.x;
      const cy = hWorld.y + offset.y;
      
      if (hunterCanvas.width > 0) {
        ctx.save();
        // 1. 초록 배경 (원형틀 배경색)
        ctx.beginPath();
        ctx.arc(cx, cy, 26, 0, Math.PI * 2);
        ctx.fillStyle = '#1b5e20';
        ctx.fill();
        
        // 2. 이미지가 원 밖으로 나가지 않게 클리핑
        ctx.clip();
        
        // 3. 배경이 완벽히 지워진 커스텀 이미지를 그대로 그립니다. (원래 색상 유지)
        ctx.globalCompositeOperation = 'source-over';
        ctx.drawImage(hunterCanvas, cx - 23, cy - 23, 46, 46);
        
        // 4. 선명한 초록색 테두리
        ctx.lineWidth = 4;
        ctx.strokeStyle = '#4caf50';
        ctx.stroke();
        
        ctx.restore();
      } else {
        // 이미지가 아직 안 불렸을 때의 폴백
        ctx.font = '40px Arial';
        ctx.fillText('👲🏼🪓', cx, cy);
      }
    }

    // 플레이어 (🐼)
    ctx.font = '36px Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('🐼', pWorld.x + offset.x, pWorld.y + offset.y);
    
    // 느낌표 (크게)
    if (state.player.showExclamation) {
      ctx.font = '50px Arial'; // 기존 30px에서 50px로 키움
      ctx.fillText('❗️', pWorld.x + offset.x, pWorld.y + offset.y - 45); // 더 위로 올림
    }
  }

  requestAnimationFrame(updateAndDraw);
}

UI.startBtn.addEventListener('click', initGame);
UI.restartBtn.addEventListener('click', initGame);
UI.replayBtn.addEventListener('click', initGame);

updateAndDraw();
